    mgmOrg = myLogic(email);
    lookupGet(mgmOrg,'mgm_organization_mapping_by_domain','key','value');
}

function myLogic(email) {
    emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (emailRegex.test(email)) {
        domain = email.split('@')[1];
        return domain.split('.')[0];
    }
}

$('AreaofInterest_KUT').split(',').map(item => item.trim()).filter(item => item !== "")
