objects.projectionScript:
function getAttributesFromCall(row)
{
  //️⃣ Grab the raw value – it can be an actual array, a JSON string,
  // or even undefined / null.
  const raw = row["CorporateAccountAddress"];

  // Normalise it to a real JavaScript array.
  let addresses;
  if (Array.isArray(raw)) {
    addresses = raw;                     // already an array
  } else if (typeof raw === "string") {
    try {
      addresses = JSON.parse(raw);       // try to parse JSON string
      if (!Array.isArray(addresses)) {
        // If the parsed value isn’t an array, treat it as a single address
        addresses = [addresses];
      }
    } catch (e) {
      // Invalid JSON – treat it as a single address (the raw string)
      addresses = [raw];
    }
  } else if (raw == null) {
    // No address at all – just return a shallow copy of the original row
    return [ { ...row } ];
  } else {
    // Anything else (object, number, etc.) – treat it as a single address
    addresses = [raw];
  }
    // 2. Logic for multiple addresses
  if (addresses?.length > 1) {
    const newRow = { ...row };

    // Find the address where MainIndicator is true
    const mainAddress = addresses.find(addr => addr.MainIndicator === true);
    // Get all addresses that are NOT the main one
    const additionalAddresses = addresses.filter(addr => addr !== mainAddress);

    // Write back to the row
    newRow["CorporateAccountAddress"] = mainAddress || addresses[0]; // Fallback to first if none marked 'true'
    newRow["AdditionalCorporateAccountAddresses"] = additionalAddresses;

    return [newRow];
  }

  // 3. If 0 or 1 address, return as is
  return [{ ...row }];
}

