objects.projectionScript:
function callOperation(row) {
  const rawAdditional = row["AdditionalCorporateAccountAddresses"];
  let additionalList = [];

  // 1. Parse the additional addresses
  try {
    if (Array.isArray(rawAdditional)) {
      additionalList = rawAdditional;
    } else if (typeof rawAdditional === "string") {
      additionalList = JSON.parse(rawAdditional);
      if (!Array.isArray(additionalList)) additionalList = [additionalList];
    }
  } catch (e) {
    // If parsing fails, treat as a single item if it exists
    if (rawAdditional) additionalList = [rawAdditional];
  }

  // 2. Map each address to a unique row
  const exploded = additionalList.map(addr => {
    // Create a shallow copy of the row
    const newRow = { ...row };

    // Set the specific address to CorporateAccountAddress
    newRow["CorporateAccountAddress"] = addr;

    // set Formattetpostal
    newRow["FormattedPostalAddressDescription"] = addr.FormattedPostalAddressDescription; 

    return newRow;
  });

  // 3. Return the array of rows (if empty, returns empty array)
  return exploded;
}

